INSERT INTO chapter_exercises (chapter_id, title, statement, expected_answer, solution, order_index, difficulty, accepted_answers) VALUES ('6fe32739-3a4b-4264-8ebb-07254764b9b4', 'Calcul du terme général', 'Soit la suite (Uₙ) définie par Uₙ = 3n² - 2n + 1. Calculer U₅ et U₁₀.', 'U₅ = 66, U₁₀ = 281', 'U₅ = 3(25) - 10 + 1 = 66 ; U₁₀ = 3(100) - 20 + 1 = 281', 0, 1, '[]'::jsonb);
INSERT INTO chapter_exercises (chapter_id, title, statement, expected_answer, solution, order_index, difficulty, accepted_answers) VALUES ('6fe32739-3a4b-4264-8ebb-07254764b9b4', 'Sens de variation', 'Montrer que la suite (Uₙ) définie par Uₙ = n/(n+1) est croissante.', 'La suite est croissante', 'Uₙ₊₁ - Uₙ = (n+1)/(n+2) - n/(n+1) = 1/((n+1)(n+2)) > 0', 1, 2, '[]'::jsonb);
INSERT INTO chapter_exercises (chapter_id, title, statement, expected_answer, solution, order_index, difficulty, accepted_answers) VALUES ('6fe32739-3a4b-4264-8ebb-07254764b9b4', 'Suite arithmétique', 'Soit une suite arithmétique de premier terme U₀ = 3 et de raison r = 5. Exprimer Uₙ en fonction de n et calculer la somme des 20 premiers termes.', 'Uₙ = 5n + 3, S₂₀ = 1010', 'Uₙ = U₀ + nr = 3 + 5n. S₂₀ = 20(U₀ + U₁₉)/2 = 20(3 + 98)/2 = 1010', 2, 2, '[]'::jsonb);
INSERT INTO chapter_exercises (chapter_id, title, statement, expected_answer, solution, order_index, difficulty, accepted_answers) VALUES ('6fe32739-3a4b-4264-8ebb-07254764b9b4', 'Suite géométrique', 'Soit une suite géométrique de premier terme U₀ = 2 et de raison q = 3. Calculer U₆ et la somme S₇ des 7 premiers termes.', 'U₆ = 1458, S₇ = 2186', 'U₆ = 2×3⁶ = 1458. S₇ = 2(3⁷-1)/(3-1) = 2×2186/2 = 2186', 3, 3, '[]'::jsonb);
INSERT INTO chapter_exercises (chapter_id, title, statement, expected_answer, solution, order_index, difficulty, accepted_answers) VALUES ('6fe32739-3a4b-4264-8ebb-07254764b9b4', 'Récurrence', 'Montrer par récurrence que pour tout n ≥ 1 : 1 + 2 + ... + n = n(n+1)/2.', 'Démonstration par récurrence', 'Init: n=1, 1 = 1×2/2 ✓. Hérédité: supposons P(n), alors 1+...+n+(n+1) = n(n+1)/2 + (n+1) = (n+1)(n+2)/2', 4, 3, '[]'::jsonb);
INSERT INTO chapter_exercises (chapter_id, title, statement, expected_answer, solution, order_index, difficulty, accepted_answers) VALUES ('6fe32739-3a4b-4264-8ebb-07254764b9b4', 'Suite récurrente', 'Soit Uₙ₊₁ = 2Uₙ - 1 avec U₀ = 3. Calculer U₁, U₂, U₃ et conjecturer la limite.', 'U₁=5, U₂=9, U₃=17, limite = +∞', 'U₁=2(3)-1=5, U₂=2(5)-1=9, U₃=2(9)-1=17. Suite divergente vers +∞', 5, 2, '[]'::jsonb);
INSERT INTO chapter_exercises (chapter_id, title, statement, expected_answer, solution, order_index, difficulty, accepted_answers) VALUES ('6fe32739-3a4b-4264-8ebb-07254764b9b4', 'Convergence', 'Soit Uₙ = (2n+1)/(n+3). Déterminer la limite de la suite.', 'lim Uₙ = 2', 'lim (2n+1)/(n+3) = lim 2n/n = 2', 6, 2, '[]'::jsonb);
INSERT INTO chapter_exercises (chapter_id, title, statement, expected_answer, solution, order_index, difficulty, accepted_answers) VALUES ('6fe32739-3a4b-4264-8ebb-07254764b9b4', 'Suite bornée', 'Montrer que la suite Uₙ = sin(n)/n est bornée et déterminer sa limite.', 'Suite bornée, limite = 0', '-1/n ≤ sin(n)/n ≤ 1/n et par le théorème des gendarmes, lim = 0', 7, 3, '[]'::jsonb);
INSERT INTO chapter_exercises (chapter_id, title, statement, expected_answer, solution, order_index, difficulty, accepted_answers) VALUES ('6fe32739-3a4b-4264-8ebb-07254764b9b4', 'Suite adjacente', 'Soient Uₙ = 1 + 1/n et Vₙ = 1 - 1/n. Montrer que ce sont des suites adjacentes.', 'Suites adjacentes de limite 1', 'Uₙ décroissante, Vₙ croissante, Uₙ - Vₙ = 2/n → 0', 8, 4, '[]'::jsonb);
INSERT INTO chapter_exercises (chapter_id, title, statement, expected_answer, solution, order_index, difficulty, accepted_answers) VALUES ('6fe32739-3a4b-4264-8ebb-07254764b9b4', 'Comportement asymptotique', 'Déterminer un équivalent simple de Uₙ = √(n²+n) - n quand n → +∞.', 'Uₙ ~ 1/2', 'Uₙ = n(√(1+1/n) - 1) ~ n × 1/(2n) = 1/2', 9, 5, '[]'::jsonb);
INSERT INTO chapter_quizzes (chapter_id, question, options, correct_answer, explanation, order_index, difficulty) VALUES ('6fe32739-3a4b-4264-8ebb-07254764b9b4', 'Quel est le terme général d''une suite arithmétique de premier terme U₀ = 5 et de raison r = 3 ?', '["Uₙ = 3n + 5", "Uₙ = 5n + 3", "Uₙ = 5 × 3ⁿ", "Uₙ = 3ⁿ + 5"]'::jsonb, 'Uₙ = 3n + 5', 'Uₙ = U₀ + nr = 5 + 3n', 0, 1);
INSERT INTO chapter_quizzes (chapter_id, question, options, correct_answer, explanation, order_index, difficulty) VALUES ('6fe32739-3a4b-4264-8ebb-07254764b9b4', 'La suite Uₙ = (-1)ⁿ est :', '["Convergente", "Divergente", "Croissante", "Bornée et convergente"]'::jsonb, 'Divergente', 'Elle oscille entre -1 et 1 sans converger', 1, 1);
INSERT INTO chapter_quizzes (chapter_id, question, options, correct_answer, explanation, order_index, difficulty) VALUES ('6fe32739-3a4b-4264-8ebb-07254764b9b4', 'Si Uₙ₊₁ = 2Uₙ avec U₀ = 1, alors Uₙ = ?', '["2ⁿ", "2n", "n²", "n!"]'::jsonb, '2ⁿ', 'Suite géométrique de raison 2', 2, 2);
INSERT INTO chapter_quizzes (chapter_id, question, options, correct_answer, explanation, order_index, difficulty) VALUES ('6fe32739-3a4b-4264-8ebb-07254764b9b4', 'La somme des n premiers entiers est :', '["n(n+1)/2", "n²/2", "n(n-1)/2", "2n+1"]'::jsonb, 'n(n+1)/2', 'Formule classique de Gauss', 3, 2);
INSERT INTO chapter_quizzes (chapter_id, question, options, correct_answer, explanation, order_index, difficulty) VALUES ('6fe32739-3a4b-4264-8ebb-07254764b9b4', 'Une suite croissante majorée est :', '["Convergente", "Divergente", "Oscillante", "Non bornée"]'::jsonb, 'Convergente', 'Théorème de la convergence monotone', 4, 3);
INSERT INTO chapter_quizzes (chapter_id, question, options, correct_answer, explanation, order_index, difficulty) VALUES ('6fe32739-3a4b-4264-8ebb-07254764b9b4', 'lim(n→+∞) (1 + 1/n)ⁿ = ?', '["e", "1", "+∞", "0"]'::jsonb, 'e', 'Définition classique du nombre e', 5, 3);
INSERT INTO chapter_quizzes (chapter_id, question, options, correct_answer, explanation, order_index, difficulty) VALUES ('6fe32739-3a4b-4264-8ebb-07254764b9b4', 'Si Uₙ ~ Vₙ et Vₙ → L ≠ 0, alors :', '["Uₙ → L", "Uₙ → 0", "Uₙ diverge", "On ne peut rien dire"]'::jsonb, 'Uₙ → L', 'Propriété des suites équivalentes', 6, 4);
INSERT INTO chapter_quizzes (chapter_id, question, options, correct_answer, explanation, order_index, difficulty) VALUES ('6fe32739-3a4b-4264-8ebb-07254764b9b4', 'La suite Uₙ = n!/nⁿ :', '["Converge vers 0", "Converge vers 1", "Diverge", "Converge vers e"]'::jsonb, 'Converge vers 0', 'Par la formule de Stirling', 7, 4);
INSERT INTO chapter_quizzes (chapter_id, question, options, correct_answer, explanation, order_index, difficulty) VALUES ('6fe32739-3a4b-4264-8ebb-07254764b9b4', 'Deux suites adjacentes :', '["Convergent vers la même limite", "Divergent", "Sont égales", "Sont monotones de même sens"]'::jsonb, 'Convergent vers la même limite', 'Définition des suites adjacentes', 8, 3);
INSERT INTO chapter_quizzes (chapter_id, question, options, correct_answer, explanation, order_index, difficulty) VALUES ('6fe32739-3a4b-4264-8ebb-07254764b9b4', 'La suite Uₙ = sin(n)/n² est :', '["Convergente vers 0", "Divergente", "Convergente vers 1", "Périodique"]'::jsonb, 'Convergente vers 0', 'Par le théorème des gendarmes : |sin(n)/n²| ≤ 1/n² → 0', 9, 5);